/**
 * SMS notification adapter.
 *
 * Formats notification payloads as SMS messages and sends them to phone numbers.
 * In this implementation, messages are collected in a sent log that can be
 * inspected (useful for testing and local development). A production
 * version would delegate to an SMS gateway API (e.g. Twilio, AWS SNS).
 */

import { Logger } from '../utils/logger.js';
import type { NotificationAdapter, NotificationPayload } from './notification-adapter.js';

export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

export interface SmsAdapterOptions {
  /** The sender phone number or short code. */
  from?: string;
  /** Map of recipient aliases/user IDs to phone numbers. */
  recipientMap?: Record<string, string>;
}

/** Maximum length for a single SMS segment. */
const SMS_MAX_LENGTH = 160;

export class SmsAdapter implements NotificationAdapter {
  readonly name = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private from: string;
  private recipientMap: Record<string, string>;

  constructor(options: SmsAdapterOptions = {}) {
    this.from = options.from ?? '+10000000000';
    this.recipientMap = options.recipientMap ?? {};
  }

  /**
   * Resolve a recipient string to a phone number.
   *
   * If the recipient starts with '+' it is treated as a phone number and
   * returned as-is. Otherwise the recipientMap is consulted. If no mapping
   * exists, the raw value is returned so delivery can still be attempted.
   */
  resolveRecipient(recipient: string): string {
    if (recipient.startsWith('+')) {
      return recipient;
    }
    return this.recipientMap[recipient] ?? recipient;
  }

  /**
   * Format a notification into an SMS-appropriate text body.
   *
   * SMS messages are short, so the subject is prepended to the body and
   * the result is truncated to fit within SMS length limits.
   */
  formatMessage(subject: string, body: string): string {
    const full = `${subject}: ${body}`;
    if (full.length <= SMS_MAX_LENGTH) {
      return full;
    }
    return full.slice(0, SMS_MAX_LENGTH - 3) + '...';
  }

  /**
   * Send a notification as an SMS message.
   */
  send(payload: NotificationPayload): boolean {
    const to = this.resolveRecipient(payload.recipient);
    const body = this.formatMessage(payload.subject, payload.body);

    const message: SmsMessage = {
      to,
      body,
      sentAt: new Date(),
    };

    this.sentMessages.push(message);
    this.logger.info(`SMS sent to ${to} from ${this.from}: "${payload.subject}"`);
    return true;
  }

  /** Get all sent messages (for testing / inspection). */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /** Clear the sent messages log. */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

/**
 * SMS notification adapter.
 *
 * Formats notifications for SMS delivery and resolves recipients to phone
 * numbers. In this implementation, messages are collected in a sent log
 * that can be inspected (useful for testing and local development). A
 * production version would delegate to an SMS gateway (e.g. Twilio).
 */

import { Logger } from '../utils/logger.js';
import type { NotificationAdapter, NotificationPayload } from './notification-adapter.js';

export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

export interface SmsAdapterOptions {
  /** The sender phone number or short code. */
  from?: string;
  /** Map of recipient aliases/user IDs to phone numbers. */
  recipientMap?: Record<string, string>;
}

export class SmsAdapter implements NotificationAdapter {
  readonly name = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private from: string;
  private recipientMap: Record<string, string>;

  constructor(options: SmsAdapterOptions = {}) {
    this.from = options.from ?? '+10000000000';
    this.recipientMap = options.recipientMap ?? {};
  }

  /**
   * Resolve a recipient string to a phone number.
   *
   * If the recipient starts with '+' it is treated as a phone number and
   * returned as-is. Otherwise the recipientMap is consulted. If no mapping
   * exists, the raw value is returned so delivery can still be attempted.
   */
  resolveRecipient(recipient: string): string {
    if (recipient.startsWith('+')) {
      return recipient;
    }
    return this.recipientMap[recipient] ?? recipient;
  }

  /**
   * Format the notification into a concise SMS body.
   *
   * SMS messages combine the subject and body into a single short text
   * since SMS has no separate subject field.
   */
  formatMessage(subject: string, body: string): string {
    return `${subject}: ${body}`;
  }

  /**
   * Send a notification as an SMS message.
   */
  send(payload: NotificationPayload): boolean {
    const to = this.resolveRecipient(payload.recipient);
    const body = this.formatMessage(payload.subject, payload.body);

    const message: SmsMessage = {
      to,
      body,
      sentAt: new Date(),
    };

    this.sentMessages.push(message);
    this.logger.info(`SMS sent to ${to} from ${this.from}: "${payload.subject}"`);
    return true;
  }

  /** Get all sent messages (for testing / inspection). */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /** Clear the sent messages log. */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms-adapter.js';
import type { NotificationPayload } from '../../src/adapters/notification-adapter.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter({
      from: '+15551234567',
      recipientMap: {
        'user-1': '+15559876543',
        'user-2': '+15551112222',
      },
    });
  });

  describe('resolveRecipient', () => {
    it('should return phone numbers unchanged', () => {
      expect(adapter.resolveRecipient('+15559876543')).toBe('+15559876543');
    });

    it('should resolve user IDs via recipientMap', () => {
      expect(adapter.resolveRecipient('user-1')).toBe('+15559876543');
      expect(adapter.resolveRecipient('user-2')).toBe('+15551112222');
    });

    it('should return raw value when no mapping exists', () => {
      expect(adapter.resolveRecipient('user-unknown')).toBe('user-unknown');
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body into a single string', () => {
      const message = adapter.formatMessage('Order Confirmation', 'Your order has been placed.');
      expect(message).toBe('Order Confirmation: Your order has been placed.');
    });
  });

  describe('send', () => {
    it('should add message to sent log and return true', () => {
      const payload: NotificationPayload = {
        recipient: '+15559876543',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const result = adapter.send(payload);

      expect(result).toBe(true);
      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15559876543');
      expect(messages[0]?.body).toBe('Order Confirmation: Your order has been placed.');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should resolve non-phone recipients before sending', () => {
      const payload: NotificationPayload = {
        recipient: 'user-1',
        subject: 'Status Update',
        body: 'Your order shipped.',
      };

      adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+15559876543');
    });

    it('should accumulate multiple messages', () => {
      adapter.send({ recipient: '+15550001111', subject: 's1', body: 'b1' });
      adapter.send({ recipient: '+15550002222', subject: 's2', body: 'b2' });

      expect(adapter.getSentMessages()).toHaveLength(2);
    });
  });

  describe('sent messages management', () => {
    it('should clear sent messages', () => {
      adapter.send({ recipient: '+15550001111', subject: 's', body: 'b' });
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return a copy of the sent messages', () => {
      adapter.send({ recipient: '+15550001111', subject: 's', body: 'b' });
      const messages = adapter.getSentMessages();
      messages.pop();
      expect(adapter.getSentMessages()).toHaveLength(1);
    });
  });

  describe('adapter interface', () => {
    it('should have name "sms"', () => {
      expect(adapter.name).toBe('sms');
    });

    it('should work with default options', () => {
      const defaultAdapter = new SmsAdapter();
      defaultAdapter.send({ recipient: '+15550001111', subject: 'hi', body: 'hello' });
      expect(defaultAdapter.getSentMessages()).toHaveLength(1);
    });
  });
});

